sql:
SELECT u.user_name, sc.uk_au_size 
FROM users u 
JOIN size_conversion sc ON u.preferred_size_id = sc.conversion_id;

SELECT COUNT(order_id) AS total_orders
FROM order_history
WHERE status = 'delivered';

external_knowledge:
- "sailing on the sea of popularity" metaphorically refers to categories that are active and frequently reviewed; 
- "more than one sail (review)" refers to the condition that the category must have more than one product review to be considered;
- "average ratings and the total number of sails" refers to the average rating and the total number of reviews for each category.

sql:
SELECT review_id, product_id
FROM reviews
WHERE rating > 3 AND size_feedback = 'runs small';

SELECT * 
FROM size_conversion 
WHERE region = 'EU';

external_knowledge:
Highly-rated = Rating 4 or above;
Satisfied customers = Users who gave high ratings;
Size according to various international standards = IT, UK/AU, US, FR, DE sizes;

sql:
SELECT COUNT(DISTINCT product_id) 
FROM order_history 
WHERE user_id = 1 AND status = 'delivered';
